    return "strided_add";
  case tianchenrv::plugin::rvv::RVVSelectedBodyOperationKind::StridedLoadUnitStore:
    return "strided_load_unit_store";
  case tianchenrv::plugin::rvv::RVVSelectedBodyOperationKind::UnitLoadStridedStore:
